SELECT 
  FROM er.tn_oom_check_item i
 WHERE i.oom_id  = #{oomId}
   AND i.item_no = #{itemNo}
   AND NOW() BETWEEN i.use_bgng_dt AND i.use_end_dt

SELECT GREATEST(COALESCE(MAX(item_no), #{startFrom} - 1), #{startFrom} - 1) + 1
  FROM er.tn_oom_check_item
 WHERE oom_id = #{oomId}
   AND item_no >= #{startFrom}

mapper.update:
UPDATE er.tn_oom_check_item
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{userId}
 WHERE oom_id  = #{oomId}
   AND item_no = #{itemNo}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

